// Overall customer churn rate for full year 2025
// Data source tables: 'crm_customers' (status, lifecycle_stage) and 'crm_customer_profile' (last_contact_at)

// NOTE: The model does not contain any industry benchmark table or field,
// so the "Industry Benchmark Churn %" column is returned as BLANK()
