DEFINE
  // Number of churned customers whose profile activity falls in 2025
  VAR _ChurnedCustomers2025 =
    CALCULATE(
      [Churned Customers],
      YEAR('crm_customer_profile'[last_contact_at]) == 2025
    )

  // Total customers considered for churn analysis in 2025
  VAR _TotalCustomers2025 =
    CALCULATE(
      [Total Customers],
      YEAR('crm_customer_profile'[last_contact_at]) == 2025
    )

  // Churn rate percentage for 2025 based on the existing measure logic
  VAR _ChurnRatePct2025 =
    CALCULATE(
      [Churn Rate pourcentage],
      YEAR('crm_customer_profile'[last_contact_at]) == 2025
    )

EVALUATE
  ROW(
    "Period", "Full Year 2025",
    "Churned Customers 2025", _ChurnedCustomers2025,
    "Total Customers 2025", _TotalCustomers2025,
    "Churn Rate 2025 (%)", _ChurnRatePct2025,
    "Industry Benchmark Churn (%)", BLANK()
  )
